import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Profile = () => {
    const [profile, setProfile] = useState({});
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        // Проверяем наличие токена
        const token = localStorage.getItem('access_token');
        if (!token) {
            // alert('You are not logged in!');
            // window.location.href = '/login'; // Замените на путь вашей страницы входа
            return;
        }

        // Запрос профиля
        axios.get('http://127.0.0.1:8000/api/employees/profile/', {
            headers: {
                Authorization: `Bearer ${token}`,
            },
        })
            .then((response) => {
                setProfile(response.data); // Устанавливаем данные профиля
                setIsLoading(false); // Убираем состояние загрузки
            })
            .catch((error) => {
                console.error('Error fetching profile:', error);
                alert('Failed to fetch profile. Please log in again.');
                window.location.href = '/login'; // Перенаправление на страницу входа
            });
    }, []);

    // Логаут
    const handleLogout = () => {
        localStorage.removeItem('access_token'); // Удаляем токен
        alert('You have been logged out.');
        window.location.href = '/login'; // Перенаправление на страницу входа
    };

    // Сообщение о загрузке
    if (isLoading) {
        return <p>Loading profile...</p>;
    }

    return (
        <div>
            <h1>User Profile</h1>
            <p>Username: {profile.username}</p>
            <p>First Name: {profile.first_name}</p>
            <p>Last Name: {profile.last_name}</p>
            <p>Email: {profile.email}</p>
            <p>Role: {profile.role}</p>
            <button onClick={handleLogout}>Logout</button>
        </div>
    );
};

export default Profile;
